class Solution:
    def maximumANDSum(self, nums, numSlots):
        n = len(nums)
        best = 0
        caps = [2] * numSlots
        def rec(idx, total):
            nonlocal best
            if idx == n:
                if total > best:
                    best = total
                return
            for s in range(numSlots):
                if caps[s] > 0:
                    caps[s] -= 1
                    rec(idx + 1, total + (nums[idx] & (s + 1)))
                    caps[s] += 1
        rec(0, 0)
        return best

