class Solution:
    def maximumANDSum(self, nums, numSlots):
        n = len(nums)
        full = 3 ** numSlots
        pow3 = [3 ** i for i in range(numSlots)]
        dp = [-1] * full
        dp[0] = 0
        ans = 0
        for mask in range(full):
            if dp[mask] < 0:
                continue
            cnt = 0
            for i in range(numSlots):
                cnt += (mask // pow3[i]) % 3
            if cnt >= n:
                if dp[mask] > ans:
                    ans = dp[mask]
                continue
            num = nums[cnt]
            for slot in range(numSlots):
                digit = (mask // pow3[slot]) % 3
                if digit < 2:
                    nm = mask + pow3[slot]
                    val = dp[mask] + (num & (slot + 1))
                    if val > dp[nm]:
                        dp[nm] = val
        return ans

