var maximumANDSum = function(nums, numSlots) {
    const n = nums.length;
    const pow3 = new Array(numSlots);
    pow3[0] = 1;
    for (let i = 1; i < numSlots; i++) pow3[i] = pow3[i - 1] * 3;
    const full = pow3[numSlots - 1] * 3;
    const dp = new Array(full).fill(-1);
    dp[0] = 0;
    let ans = 0;
    for (let mask = 0; mask < full; mask++) {
        if (dp[mask] < 0) continue;
        let cnt = 0;
        for (let i = 0; i < numSlots; i++) {
            cnt += Math.floor(mask / pow3[i]) % 3;
        }
        if (cnt >= n) {
            if (dp[mask] > ans) ans = dp[mask];
            continue;
        }
        const num = nums[cnt];
        for (let slot = 0; slot < numSlots; slot++) {
            const digit = Math.floor(mask / pow3[slot]) % 3;
            if (digit < 2) {
                const nm = mask + pow3[slot];
                const val = dp[mask] + (num & (slot + 1));
                if (val > dp[nm]) dp[nm] = val;
            }
        }
    }
    return ans;
};
